mapper.select:
select ad.id, ad.name, ad.definition_desc as definitionDesc, ad.model, ad.default_model_id as defaultModelId, ad.status, coalesce(skill_stat.skill_count, 0) as skillCount, coalesce(rule_stat.rule_count, 0) as ruleCount, coalesce(memory_stat.memory_count, 0) as memoryCount, coalesce(sub_agent_stat.sub_agent_count, 0) as subAgentCount, recent_task.exec_status as recentTaskStatus, case recent_task.exec_status when 1 then '等待执行' when 2 then '执行中' when 3 then '执行成功' when 4 then '执行失败' else null end as recentTaskStatusLabel, recent_task.update_time as latestTaskTime, ad.create_time as createTime, ad.update_time as updateTime, ad.remark from agent_definition ad left join ( select agent_id, count(1) as skill_count from agent_skill group by agent_id ) skill_stat on skill_stat.agent_id = ad.id left join ( select agent_id, count(1) as rule_count from agent_rule group by agent_id ) rule_stat on rule_stat.agent_id = ad.id left join ( select agent_id, count(1) as memory_count from agent_memory group by agent_id ) memory_stat on memory_stat.agent_id = ad.id left join ( select main_agent_id, count(1) as sub_agent_count from sub_agent_relation group by main_agent_id ) sub_agent_stat on sub_agent_stat.main_agent_id = ad.id left join lateral ( select t.exec_status, t.update_time from task t where t.agent_id = ad.id order by t.update_time desc nulls last, t.create_time desc nulls last limit 1 ) recent_task on true
and (ad.name like concat('%', #{pageRequest.keyword}, '%') or ad.definition_desc like concat('%', #{pageRequest.keyword}, '%'))
and ad.model = #{pageRequest.model}
and ad.status = #{pageRequest.status}
order by ad.update_time desc nulls last, ad.create_time desc nulls last limit #{size} offset #{offset}

select count(1)
from agent_definition ad


        and (ad.name like concat('%', #{pageRequest.keyword}, '%') or ad.definition_desc like concat('%', #{pageRequest.keyword}, '%'))


        and ad.model = #{pageRequest.model}


        and ad.status = #{pageRequest.status}

mapper.update:
update atomic_command
set skill_id = null
where skill_id in (
    select id from agent_skill
    where agent_id in #{id}
)

mapper.delete:
delete from task_detail
where task_id in (
    select id from task
    where agent_id in #{id}
)

delete from agent_memory_detail
where agent_memory_id in (
    select id from agent_memory
    where agent_id in #{id}
)

delete from sub_agent_relation
where main_agent_id in #{id}
   or sub_agent_id in #{id}

delete from agent_chat_message
where session_id in (
    select id from agent_chat_session
    where agent_id in #{id}
)
